"use client";

import { useEffect, useMemo, useState } from 'react';
import {
  Mic, MicOff, Video as VideoIcon, VideoOff, PhoneOff, MessageSquareText,
} from 'lucide-react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Appointment } from '@/types';
import DocumentComposer from '@/components/doctor/DocumentComposer';

interface VideoConsultModalProps {
  open: boolean;
  appointment: Appointment | null;
  onClose: () => void;
  onEnd: (notes?: string) => void;
  onSendPrescription?: (payload: { diagnosis: string; medications: string; instructions: string }) => void;
  onSendLab?: (payload: { testName: string; notes: string }) => void;
  onSendCertificate?: (payload: { purpose: string; diagnosis: string; restDays: number }) => void;
  videoRoomUrl?: string;
}

interface CallMessage {
  id: string;
  sender: 'doctor' | 'patient';
  text: string;
  time: string;
}

export default function VideoConsultModal({
  open,
  appointment,
  onClose,
  onEnd,
  onSendPrescription,
  onSendLab,
  onSendCertificate,
  videoRoomUrl,
}: VideoConsultModalProps) {
  const jitsiUrl = videoRoomUrl ?? appointment?.videoRoomUrl;
  const [muted, setMuted] = useState(false);
  const [cameraOff, setCameraOff] = useState(false);
  const [elapsed, setElapsed] = useState(0);
  const [note, setNote] = useState('');
  const [message, setMessage] = useState('');
  const [chat, setChat] = useState<CallMessage[]>([]);
  const [showEndDialog, setShowEndDialog] = useState(false);
  const [showComposer, setShowComposer] = useState(false);

  const displayTime = useMemo(() => {
    const mins = Math.floor(elapsed / 60).toString().padStart(2, '0');
    const secs = (elapsed % 60).toString().padStart(2, '0');
    return `${mins}:${secs}`;
  }, [elapsed]);

  useEffect(() => {
    if (!open) {
      setElapsed(0);
      setChat([]);
      setMessage('');
      setNote('');
      setShowEndDialog(false);
      setShowComposer(false);
      return;
    }
    const timer = setInterval(() => setElapsed((t) => t + 1), 1000);
    return () => clearInterval(timer);
  }, [open]);

  const sendMessage = () => {
    if (!message.trim()) return;
    const newMsg: CallMessage = {
      id: `call-msg-${Date.now()}`,
      sender: 'doctor',
      text: message.trim(),
      time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
    };
    setChat((prev) => [...prev, newMsg]);
    setMessage('');
  };

  return (
    <>
      <Dialog open={open} onOpenChange={(value) => !value && onClose()}>
        <DialogContent className="max-w-5xl">
          <DialogHeader>
            <DialogTitle className="flex items-center justify-between">
              <span>Video Consultation</span>
              <span className="text-sm text-muted-foreground">Live • {displayTime}</span>
            </DialogTitle>
          </DialogHeader>
          <div className="grid lg:grid-cols-[2fr_1fr] gap-4">
            <div className="space-y-3">
              <div className="relative aspect-video rounded-2xl bg-muted overflow-hidden flex items-center justify-center">
                {jitsiUrl ? (
                  <iframe
                    src={jitsiUrl}
                    allow="camera; microphone; fullscreen; display-capture"
                    className="w-full h-full border-0"
                    title="Video Consultation"
                  />
                ) : cameraOff ? (
                  <div className="text-center text-muted-foreground">Camera is off</div>
                ) : (
                  <div className="text-center text-muted-foreground">Waiting for video room...</div>
                )}

                <div className="absolute bottom-4 left-4 flex items-center gap-2 bg-card/80 backdrop-blur px-3 py-1 rounded-full text-xs">
                  <Avatar className="h-6 w-6">
                    <AvatarImage src={appointment?.patient?.avatar} />
                    <AvatarFallback>{appointment?.patient?.name?.[0] ?? 'P'}</AvatarFallback>
                  </Avatar>
                  {appointment?.patient?.name ?? 'Patient'}
                </div>
              </div>

              <div className="flex flex-wrap justify-center gap-2">
                <Button variant="outline" size="icon" onClick={() => setMuted((v) => !v)}>
                  {muted ? <MicOff className="h-4 w-4" /> : <Mic className="h-4 w-4" />}
                </Button>
                <Button variant="outline" size="icon" onClick={() => setCameraOff((v) => !v)}>
                  {cameraOff ? <VideoOff className="h-4 w-4" /> : <VideoIcon className="h-4 w-4" />}
                </Button>
                <Button variant="destructive" onClick={() => setShowEndDialog(true)}>
                  <PhoneOff className="h-4 w-4 mr-2" />
                  End Call
                </Button>
              </div>
            </div>

            <div className="space-y-3">
              <div className="rounded-xl border border-border p-3">
                <p className="text-sm font-medium">Consultation Notes</p>
                <Input
                  value={note}
                  onChange={(e) => setNote(e.target.value)}
                  placeholder="Add quick notes before ending..."
                  className="mt-2"
                />
              </div>

              <div className="rounded-xl border border-border overflow-hidden flex flex-col h-[360px]">
                <div className="px-3 py-2 border-b text-sm font-medium flex items-center gap-2">
                  <MessageSquareText className="h-4 w-4" />
                  In-call Chat
                </div>
                <ScrollArea className="flex-1 p-3 space-y-2">
                  {chat.length === 0 ? (
                    <p className="text-xs text-muted-foreground">No chat messages yet.</p>
                  ) : (
                    chat.map((msg) => (
                      <div
                        key={msg.id}
                        className={`text-xs rounded-lg px-3 py-2 ${msg.sender === 'doctor' ? 'bg-primary text-primary-foreground ml-auto' : 'bg-muted'}`}
                      >
                        <p>{msg.text}</p>
                        <span className="opacity-70">{msg.time}</span>
                      </div>
                    ))
                  )}
                </ScrollArea>
                <div className="p-2 border-t flex gap-2">
                  <Input
                    value={message}
                    onChange={(e) => setMessage(e.target.value)}
                    placeholder="Type a message..."
                  />
                  <Button onClick={sendMessage}>Send</Button>
                </div>
              </div>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <Dialog open={showEndDialog} onOpenChange={setShowEndDialog}>
        <DialogContent className="max-w-xl">
          <DialogHeader>
            <DialogTitle>End Consultation</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            {!showComposer ? (
              <>
                <p className="text-sm text-muted-foreground">
                  Do you want to send a document (e‑Prescription, Lab Request, or Medical Certificate) before ending?
                </p>
                <div className="flex flex-col sm:flex-row gap-2">
                  <Button variant="outline" onClick={() => setShowComposer(true)}>
                    Send Document
                  </Button>
                  <Button variant="outline" onClick={() => setShowEndDialog(false)}>
                    Back to Call
                  </Button>
                  <Button
                    variant="destructive"
                    onClick={() => {
                      setShowEndDialog(false);
                      onEnd(note);
                    }}
                  >
                    End Without Document
                  </Button>
                </div>
              </>
            ) : (
              <DocumentComposer
                onSendPrescription={(payload) => {
                  onSendPrescription?.(payload);
                  setShowEndDialog(false);
                  setShowComposer(false);
                  onEnd(note);
                }}
                onSendLab={(payload) => {
                  onSendLab?.(payload);
                  setShowEndDialog(false);
                  setShowComposer(false);
                  onEnd(note);
                }}
                onSendCertificate={(payload) => {
                  onSendCertificate?.(payload);
                  setShowEndDialog(false);
                  setShowComposer(false);
                  onEnd(note);
                }}
              />
            )}
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}
